mapper.select:
SELECT
FROM ai_recommend_item r INNER JOIN ai_recommend_record rec ON rec.recommend_id = r.recommend_id INNER JOIN fund_info fi ON fi.fund_id = r.fund_id LEFT JOIN fund_company c ON c.company_id = fi.company_id LEFT JOIN pm ON pm.fund_id = fi.fund_id
rec.status = 'SUCCESS'
AND rec.user_id = #{userId}
AND rec.recommend_scene = #{scene}
ORDER BY rec.created_time DESC, r.display_order ASC, r.item_id ASC

SELECT
FROM ai_recommend_item r INNER JOIN ai_recommend_record rec ON rec.recommend_id = r.recommend_id INNER JOIN fund_info fi ON fi.fund_id = r.fund_id LEFT JOIN fund_company c ON c.company_id = fi.company_id LEFT JOIN pm ON pm.fund_id = fi.fund_id
rec.status = 'SUCCESS'
AND rec.user_id = #{userId}
AND rec.recommend_scene = #{scene}
ORDER BY rec.created_time DESC, r.display_order ASC
LIMIT #{limit}
